using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    Console.ResetColor();
    return 1;
}

// --- Shared state ---
int searchCount = 0;
var notebook = new Notebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("Mozilla/5.0 (ResearchAgent/1.0)");

// --- Build the AI client with automatic tool invocation ---
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// --- Register tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWebAsync, "search_web",
        "Search the web for information on a query. Returns titles, URLs, and snippets."),
    AIFunctionFactory.Create(notebook.AddNote, "add_note",
        "Save a research note to remember later. Record key findings, facts, and data points."),
    AIFunctionFactory.Create(notebook.GetNotes, "get_notes",
        "Retrieve all saved research notes to review before writing the final summary."),
};

const string systemPrompt = """
    You are a thorough research agent. Given a topic, you:
    1. Break it into 2-4 focused search queries.
    2. Call search_web for each query.
    3. Call add_note to save important findings (facts, statistics, quotes, sources).
    4. Call get_notes to review everything collected.
    5. Write a comprehensive, well-structured summary with sections and source citations.

    Be thorough but efficient. Avoid redundant searches.
    """;

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        \U0001f50d AI Research Agent          ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or       ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(topic) ||
        topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    notebook.Clear();
    searchCount = 0;

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research this topic thoroughly: {topic}"),
    };

    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"\n\U0001f52c Researching \"{topic}\"...\n");
    Console.ResetColor();

    try
    {
        var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("\n═══════════════ Research Summary ═══════════════\n");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"\n[Notes taken: {notebook.Count} | Web searches: {searchCount}]");
        Console.ResetColor();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

return 0;

// ---------------------------------------------------------------------------
// Tool: Web Search (DuckDuckGo HTML)
// ---------------------------------------------------------------------------
async Task<string> SearchWebAsync(
    [Description("The search query")] string query,
    [Description("Max results to return (default 5)")] int maxResults = 5)
{
    searchCount++;
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  \U0001f50e Searching: \"{query}\"");
    Console.ResetColor();

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await httpClient.GetStringAsync(url);
        var results = ParseSearchResults(html, maxResults);

        if (results.Count == 0)
            return "No results found for this query.";

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for \"{query}\":");
        sb.AppendLine();
        for (int i = 0; i < results.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {results[i].Title}");
            sb.AppendLine($"    URL: {results[i].Url}");
            sb.AppendLine($"    {results[i].Snippet}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

// ---------------------------------------------------------------------------
// HTML parsing helpers
// ---------------------------------------------------------------------------
List<SearchResult> ParseSearchResults(string html, int max)
{
    var results = new List<SearchResult>();

    var resultPattern = new Regex(
        @"<a[^>]*class=""result__a""[^>]*href=""(?<url>[^""]*)""[^>]*>(?<title>.*?)</a>",
        RegexOptions.Singleline);

    var snippetPattern = new Regex(
        @"<a[^>]*class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline);

    var linkMatches = resultPattern.Matches(html);
    var snippetMatches = snippetPattern.Matches(html);

    for (int i = 0; i < linkMatches.Count && results.Count < max; i++)
    {
        var rawUrl = WebUtility.HtmlDecode(linkMatches[i].Groups["url"].Value);
        var uddg = Regex.Match(rawUrl, @"uddg=([^&]+)");
        var finalUrl = uddg.Success
            ? Uri.UnescapeDataString(uddg.Groups[1].Value)
            : rawUrl;

        var snippet = i < snippetMatches.Count
            ? StripHtml(snippetMatches[i].Groups["snippet"].Value)
            : "(No snippet)";

        results.Add(new SearchResult(
            Title: StripHtml(linkMatches[i].Groups["title"].Value),
            Url: finalUrl,
            Snippet: snippet));
    }

    return results;
}

string StripHtml(string html) =>
    WebUtility.HtmlDecode(Regex.Replace(html, "<[^>]+>", " ")).Trim();

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------
record SearchResult(string Title, string Url, string Snippet);

/// <summary>Simple in-memory notebook for storing research notes.</summary>
class Notebook
{
    private readonly List<string> _notes = [];

    public int Count => _notes.Count;

    public string AddNote(
        [Description("The note to save")] string note,
        [Description("Optional category: fact, quote, statistic, insight")] string? category = null)
    {
        var entry = category is not null ? $"[{category}] {note}" : note;
        _notes.Add(entry);
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  \U0001f4dd Note #{_notes.Count} saved{(category is not null ? $" ({category})" : "")}");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved.";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"All research notes ({_notes.Count} total):");
        sb.AppendLine();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"  [{i + 1}] {_notes[i]}");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

