         [Description("The note to save")] string note,
         [Description("Optional category: fact, quote, statistic, insight")] string? category = null)
     {
         var entry = category is not null ? $"[{category}] {note}" : note;
         _notes.Add(entry);
         Console.ForegroundColor = ConsoleColor.DarkGray;
         Console.WriteLine($"  \U0001f4dd Note #{_notes.Count} saved{(category is not null ? $" ({category})" : "")}");
         Console.ResetColor();
         return $"Note #{_notes.Count} saved.";
     }

     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         var sb = new StringBuilder();
         sb.AppendLine($"All research notes ({_notes.Count} total):");
         sb.AppendLine();
         for (int i = 0; i < _notes.Count; i++)
             sb.AppendLine($"  [{i + 1}] {_notes[i]}");
         return sb.ToString();
     }

     public void Clear() => _notes.Clear();
 }

